const t={hostControl:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Administra el host Linux de la impresora — revisa su estado y el del sistema operativo. Los servicios, la limpieza de disco y los ajustes del sistema llegarán en fases posteriores."}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"¿Qué es esto?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind se ejecuta en el pequeño ordenador Linux de la impresora (el host). Este panel lee el estado en vivo de esa máquina y de su sistema operativo para que detectes problemas — una CPU sobrecalentada, un disco lleno, un reloj sin sincronizar — sin abrir una terminal."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Lee de un vistazo las tarjetas de temperatura de CPU, memoria, disco y red."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Observa la tabla de procesos principales para ver qué está usando la CPU ahora."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Deja la actualización automática activada para una vista en vivo, o desactívala y actualiza manualmente."}},topics:{glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Términos usados aquí"}}},monitor:{title:{t:0,b:{t:2,i:[{t:3}],s:"Leer el monitor"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Todo aquí es de solo lectura. Las barras se vuelven ámbar a partir del 75 % y rojas a partir del 90 %. La temperatura de la CPU se vuelve ámbar a 70 °C y roja a 80 °C. La advertencia de limitación solo aparece en placas que la informan (principalmente Raspberry Pi)."}}}},glossary:{host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Host"}},def:{t:0,b:{t:2,i:[{t:3}],s:"El pequeño ordenador Linux (p. ej. una Raspberry Pi o BTT CB1) que ejecuta Klipper, Moonraker y FilaMind — separado de los microcontroladores de la impresora."}}},load:{term:{t:0,b:{t:2,i:[{t:3}],s:"Carga media"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Cuántos procesos esperaban para ejecutarse, promediados sobre 1 / 5 / 15 minutos. A grandes rasgos: un valor cercano al número de núcleos significa que la CPU está ocupada; muy por encima significa que está sobrecargada."}}},swap:{term:{t:0,b:{t:2,i:[{t:3}],s:"Swap"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Espacio de disco usado como desbordamiento cuando la RAM se llena. Un uso intenso de swap ralentiza el host — señal de que le falta memoria."}}},throttle:{term:{t:0,b:{t:2,i:[{t:3}],s:"Limitación (throttling)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Cuando la placa reduce su velocidad para protegerse — normalmente por una fuente de alimentación insuficiente (subtensión) o sobrecalentamiento. Se informa sobre todo en Raspberry Pi."}}},ntp:{term:{t:0,b:{t:2,i:[{t:3}],s:"NTP / sincronización del reloj"}},def:{t:0,b:{t:2,i:[{t:3}],s:"El Protocolo de Tiempo de Red mantiene preciso el reloj del host. Un reloj sin sincronizar puede romper timelapses, registros y certificados TLS."}}},locale:{term:{t:0,b:{t:2,i:[{t:3}],s:"Configuración regional (locale)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Los ajustes de idioma y distribución de teclado del host, que el sistema operativo usa para texto, fechas y el mapa de teclado de la consola."}}}}},monitor:{refresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualizar"}},autoRefresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualización automática"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Leyendo el estado del host…"}},host:{t:0,b:{t:2,i:[{t:3}],s:"Host"}},hostname:{t:0,b:{t:2,i:[{t:3}],s:"Nombre de host"}},distro:{t:0,b:{t:2,i:[{t:3}],s:"Sistema operativo"}},kernel:{t:0,b:{t:2,i:[{t:3}],s:"Kernel"}},uptime:{t:0,b:{t:2,i:[{t:3}],s:"Tiempo activo"}},cpu:{t:0,b:{t:2,i:[{t:3}],s:"CPU"}},temp:{t:0,b:{t:2,i:[{t:3}],s:"Temperatura"}},load:{t:0,b:{t:2,i:[{t:3}],s:"Carga (1·5·15 min)"}},cores:{t:0,b:{t:2,i:[{t:3}],s:"Núcleos"}},throttled:{t:0,b:{t:2,i:[{t:3}],s:"Limitado"}},memory:{t:0,b:{t:2,i:[{t:3}],s:"Memoria"}},ram:{t:0,b:{t:2,i:[{t:3}],s:"RAM"}},swap:{t:0,b:{t:2,i:[{t:3}],s:"Swap"}},disk:{t:0,b:{t:2,i:[{t:3}],s:"Disco"}},network:{t:0,b:{t:2,i:[{t:3}],s:"Red"}},iface:{t:0,b:{t:2,i:[{t:3}],s:"Interfaz"}},ip:{t:0,b:{t:2,i:[{t:3}],s:"Dirección IP"}},ssid:{t:0,b:{t:2,i:[{t:3}],s:"Wi-Fi"}},signal:{t:0,b:{t:2,i:[{t:3}],s:"Señal"}},timeLocale:{t:0,b:{t:2,i:[{t:3}],s:"Hora y configuración regional"}},timezone:{t:0,b:{t:2,i:[{t:3}],s:"Zona horaria"}},ntp:{t:0,b:{t:2,i:[{t:3}],s:"Sincronización del reloj"}},synced:{t:0,b:{t:2,i:[{t:3}],s:"Sincronizado"}},syncing:{t:0,b:{t:2,i:[{t:3}],s:"Sincronizando…"}},ntpOff:{t:0,b:{t:2,i:[{t:3}],s:"Desactivado"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Idioma"}},keymap:{t:0,b:{t:2,i:[{t:3}],s:"Distribución de teclado"}},topProcesses:{t:0,b:{t:2,i:[{t:3}],s:"Procesos principales"}},command:{t:0,b:{t:2,i:[{t:3}],s:"Comando"}},cpuPct:{t:0,b:{t:2,i:[{t:3}],s:"CPU %"}},memPct:{t:0,b:{t:2,i:[{t:3}],s:"MEM %"}},pid:{t:0,b:{t:2,i:[{t:3}],s:"PID"}}}}};export{t as default};
